#include <bits/stdc++.h>
using namespace std;
int n,len[50];
void dfs(int n,int c) {
	if(n==1||n==len[c-1]+1) {
		cout<<"m";
		return;
	} else if(n<=3||n>len[c-1]&&n<=len[c]-len[c-1]) {
		cout<<"o";
		return;
	} else if(n>len[c-1]+1+2+c) {
		n-=len[c-1]+1+2+c;
	}
	if(n<=len[c-1]) {
		dfs(n,c-1);
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	len[0]=3;
	int i;
	for(i=0; len[i-1]<n; i++) {
		len[i]=2*len[i-1]+1+2+i;
	}
	dfs(n,i-1);
	return 0;
}
